function setTooltips(){[...document.querySelectorAll('[data-bs-toggle="tooltip"]')].map((tooltipTriggerEl=>new bootstrap.Tooltip(tooltipTriggerEl))),[...document.querySelectorAll('[data-bs-toggle="popover"]')].map((popoverTriggerEl=>new bootstrap.Popover(popoverTriggerEl)))}function swapAppTheme(appTheme){document.getElementById("theme-style").href=appTheme?`css/${appTheme}-bootstrap.css`:"bootstrap-source/dist/css/bootstrap.css"}function handleComponentSelect(value){switch(value){case"accordion":addAccordion();break;case"alert":addAlert();break;case"badge":addBadge();break;case"carousel":addCarousel();break;case"form":addForm();break;case"horizontalForm":addHorizontalForm();break;case"pagination":addPagination();break;case"progress":addProgress();break;case"spinner":addSpinner();break;case"table":addTable();break;case"typography":addTypography();break;case"validation":addValidation();break;default:document.getElementById("demo-container").innerHTML=""}}function toggleTheme(theme){console.log(`Toggling theme to ${theme}`);const html=document.documentElement;if(localStorage.setItem("bs-theme",theme),"system"===theme){const prefersDark=window.matchMedia("(prefers-color-scheme: dark)").matches;html.setAttribute("data-bs-theme",prefersDark?"dark":"light")}else html.setAttribute("data-bs-theme",theme);showActiveTheme(theme)}function showActiveTheme(theme){const themeButton=document.querySelector("#bd-theme-text"),activeBtn=document.querySelector(`[data-bs-theme-value="${theme}"]`);if(themeButton&&activeBtn){const activeIcon=activeBtn.querySelector("i"),btnIcon=themeButton.querySelector("i");activeIcon&&btnIcon&&(btnIcon.className=activeIcon.className,btnIcon.classList.remove("me-2"))}document.querySelectorAll("[data-bs-theme-value]").forEach((el=>{el.classList.remove("active"),el.setAttribute("aria-pressed","false")})),activeBtn&&(activeBtn.classList.add("active"),activeBtn.setAttribute("aria-pressed","true"))}window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",(()=>{"system"===getLocalStorageTheme()&&toggleTheme("system")}));